<style>
@import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@400;700&display=swap');

/* === 容器设计 === */
#magic-options-wrapper {
    /* 核心背景：深色 + 神秘暗纹 */
    background-color: #111114;
    background-image: 
        radial-gradient(circle at 50% 50%, rgba(50, 40, 30, 0.1) 0%, rgba(0,0,0,0) 70%),
        repeating-linear-gradient(45deg, rgba(139, 115, 85, 0.03) 0px, rgba(139, 115, 85, 0.03) 1px, transparent 1px, transparent 10px);

    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);

    /* 边框：双线金边 */
    border: 1px solid rgba(139, 115, 85, 0.3);
    border-bottom: 1px dashed rgba(139, 115, 85, 0.2);
    box-shadow: 
        inset 0 0 30px rgba(0,0,0,0.8), /* 内阴影 */
        0 0 15px rgba(0,0,0,0.5);      /* 外阴影 */

    border-radius: 4px 4px 0 0;
    padding: 20px 15px 15px 15px;
    margin-bottom: 0;
    position: relative;
    z-index: 100;

    font-family: 'Cinzel', serif;
    color: #bfbfbf;
    overflow: hidden; /* 限制装饰溢出 */
}

/* === 神秘角标花纹 (纯CSS绘制) === */
.corner-deco {
    position: absolute;
    width: 40px;
    height: 40px;
    border: 2px solid #8b7355;
    pointer-events: none;
    transition: all 0.5s ease;
    opacity: 0.8;
}

.top-left {
    top: 5px; left: 5px;
    border-right: none; border-bottom: none;
    background: linear-gradient(135deg, rgba(139,115,85,0.2) 0%, transparent 50%);
}
.top-left::after {
    content: ''; position: absolute; top: 0; left: 0;
    width: 6px; height: 6px; background: #ffd700;
    box-shadow: 0 0 10px #ffd700;
}

.top-right {
    top: 5px; right: 5px;
    border-left: none; border-bottom: none;
    background: linear-gradient(-135deg, rgba(139,115,85,0.2) 0%, transparent 50%);
}
.top-right::after {
    content: ''; position: absolute; top: 0; right: 0;
    width: 6px; height: 6px; background: #ffd700;
    box-shadow: 0 0 10px #ffd700;
}

