    color: #554433;
    font-size: 10px;
    opacity: 0.6;
}

/* === 选项网格 === */
.magic-grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: 10px;
}
@media (min-width: 500px) { .magic-grid { grid-template-columns: 1fr 1fr; } }

/* === 魔法按钮 (重设计) === */
.magic-option-btn {
    /* 深邃背景 */
    background: linear-gradient(90deg, transparent 0%, rgba(45, 35, 25, 0.6) 20%, rgba(45, 35, 25, 0.6) 80%, transparent 100%);
    border: 1px solid rgba(139, 115, 85, 0.3);
    border-left: 2px solid #8b7355; /* 左侧加粗金边 */
