    box-shadow: 0 0 15px rgba(255, 215, 0, 0.15);
}
.magic-option-btn:hover::before { color: #ffd700; }

/* 发送状态 */
.magic-sending {
    background: rgba(139, 0, 0, 0.6) !important;
    border-color: #ff4500 !important;
    color: #ffcccc !important;
}

/* 动画 */
.magic-fade-in { animation: fadeIn 0.6s ease forwards; opacity: 0; }
@keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
</style>

<script>
(function() {
    // === 逻辑部分 (保持你最满意的发送逻辑) ===
    const triggerQuickReply = (text) => {
        if (!text || ['…', '...'].includes(text.trim()) || text.trim().length === 0) return;
        if (typeof triggerSlash === 'function') {
            triggerSlash(`/send ${text}|/trigger`);
        } else {
            console.warn('SillyTavern environment not detected. Would send:', text);
        }
    };

    const sendToChatBox = (text) => {
        if (!text || ['…', '...'].includes(text.trim()) || text.trim().length === 0) return;
        try {
            let $textarea = $(parent.document).find('#send_textarea');
            if ($textarea.length === 0) $textarea = $('#send_textarea');

            if ($textarea.length === 0) {
                triggerQuickReply(text);
                return;
            }

            const currentContent = $textarea.val() || '';
            if (currentContent.includes(text.trim())) return;

            const separator = currentContent.trim() ? '\n' : '';
            const newContent = currentContent + separator + text.trim();

            $textarea.val(newContent);
            $textarea.trigger('input');
            $textarea.focus();
        } catch (error) {
            triggerQuickReply(text);
        }
    };

    // === 初始化 UI ===
    function initOptions() {
        if (typeof getCurrentMessageId !== 'function' || typeof getChatMessages !== 'function') return;

        const msgId = getCurrentMessageId();
        const messages = getChatMessages(msgId);
        if (!messages || messages.length === 0) return;

        const lastMsg = messages[0];
        if (!lastMsg || !lastMsg.message) return;

        const match = lastMsg.message.match(/<options>((?:(?!<options>).)*?)<\/options>/s);
        const $wrapper = $('#magic-options-wrapper');
        const $grid = $('#magic-options-grid');

        if (match && match[1]) {
            $grid.empty();
            $wrapper.show();

            const options = match[1].split('|').map(o => o.trim()).filter(o => o);
            if(options.length === 0) { $wrapper.hide(); return; }

            options.forEach((optText, index) => {
                const $btn = $('<div>')
                    .addClass('magic-option-btn magic-fade-in')
                    .css('animation-delay', (index * 0.1) + 's')
                    .text(optText);

                $btn.on('click', function(e) {
                    e.stopPropagation();
                    let textToSend = $(this).text().trim();
                    textToSend = textToSend.replace(/^\d+\.\s*/, ''); 

                    $(this).addClass('magic-sending');
                    sendToChatBox(textToSend);

                    setTimeout(() => { $wrapper.slideUp(500); }, 250);
                });
                $grid.append($btn);
            });
        } else {
            $wrapper.hide();
        }
    }
    setTimeout(initOptions, 600);
})();
</script>
